import React, { useState } from 'react';
import { NotesProvider } from './context/NotesContext';
import Sidebar from './components/Layout/Sidebar';
import SplitLayout from './components/Layout/SplitLayout';
import TopBar from './components/UI/TopBar';
import ErrorBoundary from './components/ErrorBoundary';
import { useNotes } from './context/NotesContext';
import useResizablePanels from './hooks/useResizablePanels';
import ResizeHandle from './components/UI/ResizeHandle';
import PanelControls from './components/UI/PanelControls';
import './styles/main.css';

function AppContent() {
  const { currentNote } = useNotes();
  const [showBackButton, setShowBackButton] = useState(false);
  const {
    sidebarWidth,
    editorWidth,
    isResizing,
    handleMouseDown,
    containerRef,
    previewWidth,
    resetLayout,
    maximizeSidebar,
    maximizeEditor,
    maximizePreview,
    togglePanel
  } = useResizablePanels();

  return (
    <div className="app-container" ref={containerRef}>
      <Sidebar style={{ width: `${sidebarWidth}px` }} />
      <ResizeHandle
        onMouseDown={(e) => handleMouseDown(e, 'sidebar')}
        isActive={isResizing === 'sidebar'}
      />
      {currentNote && (
        <>
          <SplitLayout
            onBack={() => setShowBackButton(false)}
            editorWidth={editorWidth}
            previewWidth={previewWidth}
            onEditorResize={(e) => handleMouseDown(e, 'editor')}
            isResizingEditor={isResizing === 'editor'}
          />

        </>
      )}
    </div>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <NotesProvider>
        <AppContent />
      </NotesProvider>
    </ErrorBoundary>
  );
}

export default App;
